files.content:
.mrg-form {
  color: var(--mrg-semantic-color-foreground-primary);
  display: flex;
  flex-direction: column;
  font-family: var(--mrg-semantic-font-family-prose);
  gap: var(--mrg-semantic-space-stack-lg);
  inline-size: 100%;
  min-inline-size: 0;
}

.mrg-form[data-layout="compact"] {
  gap: var(--mrg-semantic-space-stack-sm);
}

import { forwardRef, type FormHTMLAttributes } from "react";

import "./form.css";

export interface FormProps extends FormHTMLAttributes<HTMLFormElement> {
  readonly layout?: "stacked" | "compact";
}

export const Form = forwardRef<HTMLFormElement, FormProps>(function Form(
  { className, layout = "stacked", ...nativeProps },
  ref,
) {
  return (
    <form
      {...nativeProps}
      className={className === undefined ? "mrg-form" : `mrg-form ${className}`}
      data-layout={layout}
      data-slot="form"
      ref={ref}
    />
  );
});

Form.displayName = "Form";
